class Solution:
    def findTargetSumWays(self, nums, target):
        n = len(nums)
        count = 0
        for mask in range(1 << n):
            s = 0
            for i in range(n):
                if (mask >> i) & 1:
                    s += nums[i]
                else:
                    s -= nums[i]
            if s == target:
                count += 1
        return count

