class Solution:
    def findTargetSumWays(self, nums, target):
        from collections import defaultdict
        dp = defaultdict(int)
        dp[0] = 1
        for x in nums:
            nd = defaultdict(int)
            for s, c in dp.items():
                nd[s + x] += c
                nd[s - x] += c
            dp = nd
        return dp.get(target, 0)

