var findTargetSumWays = function(nums, target) {
    let dp = new Map();
    dp.set(0, 1);
    for (const x of nums) {
        const nd = new Map();
        for (const [s, c] of dp) {
            nd.set(s + x, (nd.get(s + x) || 0) + c);
            nd.set(s - x, (nd.get(s - x) || 0) + c);
        }
        dp = nd;
    }
    return dp.get(target) || 0;
};
